select count(1)
from inf_project_space_directory
where project_id = #{projectId}

select count(1)
from inf_project_space_directory
where project_id = #{projectId}
  and directory_code = #{directoryCode}

mapper.insert:
insert into inf_project_space_directory (
    project_id, parent_id, template_id, directory_code, directory_name, directory_level, directory_type,
    full_path, required_flag, compliance_status, archive_status, sort_order, create_by, create_time, remark
) values (
    #{projectId}, #{parentId}, #{templateId}, #{directoryCode}, #{directoryName}, #{directoryLevel}, #{directoryType},
    #{fullPath}, #{requiredFlag}, #{complianceStatus}, #{archiveStatus}, #{sortOrder}, #{createBy}, sysdate(), #{remark}
)

mapper.update:
update inf_project_space_directory
compliance_status = #{complianceStatus}, archive_status = #{archiveStatus}, remark = #{remark}, update_by = #{updateBy}, update_time = sysdate()
where directory_id = #{directoryId}
